from anthropic import AsyncAnthropic

class ClaudeService:
    def __init__(self, api_key: str):
        self.client = AsyncAnthropic(api_key=api_key)

    async def create_message(self, req: CreateMessageRequest):
        response = await self.client.messages.create(
            model=req.model,
            max_tokens=req.max_tokens,
            system=req.system,
            messages=[m.model_dump() for m in req.messages],
            temperature=req.temperature,
        )
        return {
            "id": response.id,
            "model": response.model,
            "stop_reason": response.stop_reason,
            "content": response.content,
            "usage": {
                "input_tokens": response.usage.input_tokens,
                "output_tokens": response.usage.output_tokens,
            },
        }

from fastapi.responses import StreamingResponse

@router.post("/stream")
async def stream_message(
    body: CreateMessageRequest,
    claude: ClaudeService = Depends(get_claude_service),
):
    async def event_gen():
        async for chunk in claude.stream_message(body):
            yield f"data: {chunk}\n\n"

    return StreamingResponse(event_gen(), media_type="text/event-stream")

async def run_with_tools(self, req):
    messages = [m.model_dump() for m in req.messages]

    while True:
        response = await self.client.messages.create(
            model=req.model,
            max_tokens=req.max_tokens,
            messages=messages,
            tools=self.tools_schema,
        )

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason != "tool_use":
            return response

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = await self.tool_executor.execute(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        messages.append({"role": "user", "content": tool_results})
